        String getNativeIdentity(List adLinks, String samAccName) {        
        if (adLinks != links && !Util.isEmpty(adLinks)) {  
        for (Link link: adLinks) {
        if (samAccName.equalsIgnoreCase(link.getAttribute("sAMAccountName"))) {
        return link.getNativeIdentity();
        }
        }
        }
        return null;
        }

        public void scheduleWorkflow(String workflowName, String caseName, long startTime, Attributes wfArgs) {
        log.trace("Started scheduleWorkflow*******");

        if (null == caseName || "".equals(caseName.trim())) {
        caseName = "Rest API " + workflowName + " - " + identityName;
        }

        Workflow eventWorkflow = context.getObject(Workflow.class, workflowName);
        if (null == eventWorkflow) {
        log.trace("Could not find a workflow named: " + workflowName);
        throw new GeneralException("Invalid worklfow: " + workflowName);
        }


        // Ask the Request Processor to start the workflow 5 seconds from now.
        // Append the time stamp to the workflow case name to ensure it's unique.
        long launchTime = startTime;


        // Build out a map of arguments to pass to the Request Scheduler.
        Attributes reqArgs = new Attributes();
        reqArgs.put(StandardWorkflowHandler.ARG_REQUEST_DEFINITION, sailpoint.request.WorkflowRequestExecutor.DEFINITION_NAME);
        reqArgs.put(sailpoint.workflow.StandardWorkflowHandler.ARG_WORKFLOW, workflowName);
        reqArgs.put(sailpoint.workflow.StandardWorkflowHandler.ARG_REQUEST_NAME, caseName);
        reqArgs.put("requestName", caseName);

        wfArgs.put("workflow", eventWorkflow.getName());
        reqArgs.putAll(wfArgs);

        // Use the Request Launcher to schedule the workflow reqeust.  This requires
        // a Request object to store the properties of the request item.
        Request req = new Request();
        RequestDefinition reqdef = context.getObject(RequestDefinition.class, "Workflow Request");
        req.setDefinition(reqdef);
        req.setEventDate(new Date(launchTime));
        //req.setOwner(id);
        req.setName(caseName);
        req.setAttributes(reqdef, reqArgs);

        // Schedule the work flow via the request manager.
        RequestManager.addRequest(context, req);
        }
        Date date = new Date();
        String workFlowName = "LCM Provisioning";
        Attributes newWFArgs = null;
        Identity identity = null;
        AccountRequest accountRequest = null;
        List userDetails = new ArrayList();
        List newAcctReqList = null;
        ProvisioningPlan newPlan = null;
        String caseName = null;
        userDetails = formModel.get("userDetails");
        log.trace("Starting userDetails******" + userDetails +" ********formModel.keySet()"+formModel.keySet());
        for (String identityName: userDetails) {
        identity = context.getObjectByName(Identity.class, identityName);
        List adLinks = iu.getIdFilteredActiveADLinks(identity); 
        log.trace("Check for identityName******" + identityName);
        for (String key: formModel.keySet()) {
        log.trace("Keyyyyyyy***" + key);
        log.trace("key Starts with *******" + key.startsWith(identityName));
        if (key.startsWith(identityName)) {
        log.trace("Plan generation for " + identityName);
        String[] dummy = key.split("@");
        if (dummy.length == 4) {
        String samAccName = dummy[1];
        String appName = dummy[2];
        String exp = dummy[3];
        if ("NewExp".equalsIgnoreCase(exp)) {        
        Date expDate = formModel.get(key);
        log.trace("expDate****" + expDate);
        newPlan = new ProvisioningPlan();        
        accountRequest = new AccountRequest();
        newPlan.setIdentity(identity);
        String nativeIden = getNativeIdentity(adLinks, samAccName);
        log.trace("native identity***" + nativeIden);
        accountRequest.setNativeIdentity(nativeIden);
        accountRequest.setApplication(appName);
        accountRequest.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);
        accountRequest.add(new AttributeRequest("accountExpires", ProvisioningPlan.Operation.Set, expDate));
        newAcctReqList = new ArrayList();
        newAcctReqList.add(accountRequest);
        newPlan.setAccountRequests(newAcctReqList);
        newWFArgs = new Attributes();
        newWFArgs.put("identityName", identityName);
        newWFArgs.put("plan", newPlan);
        newWFArgs.put("source", "LCM");
        newWFArgs.put("flow", "RequestAccess");
        newWFArgs.put("approvalScheme", "none");
        newWFArgs.put("notificationScheme", "none");
        newWFArgs.put("policyScheme", "none");
        newWFArgs.put("autoVerifyIdentityRequest", true);
        caseName = "Run-Request-" + workFlowName + "-" + identityName;
        log.trace("*****caseName*****" + caseName);
        scheduleWorkflow(workFlowName, caseName, date.getTime(), newWFArgs);
        }
        }
        }
        }
        }

        import java.text.SimpleDateFormat;
        import java.util.ArrayList;
        import java.util.Collections;
        import java.util.Date;
        import java.util.List;
        import sailpoint.api.IdentityService;
        import sailpoint.object.Identity;
        import sailpoint.object.Link;
        import sailpoint.tools.Util;
        import org.ascn.objectutils.IdentityUtils;
		
		IdentityUtils iu = new IdentityUtils();
	      String adExpAttrName = "accountExpires"; //link schema name for AD attribute
        String ctExpDate = "ctrexpDt"; //identity mapping name for ct exp date                        
        List collectionDateList = null;
        Identity identity = null;
        log.trace("Final AD appNames****** " + appNames);
        int counter = 0;
        SimpleDateFormat format=new SimpleDateFormat("yyyy-MM-dd");
        for (String identityName: formModel.get("userDetails")) {
        identity = context.getObjectByName(Identity.class, identityName);			
        String finalExpDate = null;
        Date expDate = null;
        collectionDateList = new ArrayList();
        log.error("OutPot of reading of user is*******" + identityName);        
        if (identity.getAttribute(ctExpDate) != null) {
        log.error("End user expiry date is *******" + identity.getAttribute(ctExpDate));
        collectionDateList.add(format.parse(identity.getAttribute(ctExpDate)));
        }
        log.error("OutPut of identity of intial  collectionDateList is*******" + collectionDateList);
        log.error("Check for formModel identityName******" + identityName);
        for (String key: formModel.keySet()) {
        if (key.startsWith(identityName)) {
        log.error("expiration date set to be " + identityName);
        String[] dummy = key.split("@");
        if (dummy.length == 4) {
        String exp = dummy[3];
        if ("NewExp".equalsIgnoreCase(exp)) {
        expDate = formModel.get(key);
        log.error("expDate****" + expDate);
        collectionDateList.add(expDate);
        }
        }
        }
        }        
        log.error("OutPut of form of intial  collectionDateList is*******" + collectionDateList);
        List links = iu.getIdFilteredActiveADLinks(identity);    
        log.error("Identity ******" +identityName +"**********"+links);
        if (null != links && !Util.isEmpty(links)) {
        for (Link link: links) {
        if (link.getAttribute(adExpAttrName) != null @and!"never".equalsIgnoreCase(link.getAttribute(adExpAttrName))) {
        expDate = Util.stringToDate(link.getAttribute(adExpAttrName));
        log.error("AD app Name details******" + expDate.toString());
        collectionDateList.add(expDate);
        }
        }
        }

        log.error("OutPut of Account level of collectionDateList is*******" + collectionDateList);
        if (null != collectionDateList && !Util.isEmpty(collectionDateList)) {
        Collections.sort(collectionDateList);
        Date fDate = collectionDateList.get(collectionDateList.size() - 1);
        finalExpDate = Util.dateToString(fDate, "yyyy-MM-dd");
        }
        log.error("OutPut of identity of ctExpDate is*******" + identityName);
        log.error("OutPut of identity of finalExpDate is*******" + finalExpDate);
        if (finalExpDate != null) {
        identity.setAttribute(ctExpDate, finalExpDate);
        context.saveObject(identity);
        
        counter++;
        }
        if (counter % 4 == 0) {
        context.commitTransaction();
        }
        }
        if (counter > 0) {
        context.commitTransaction();
        }
